import React, { useState } from "react";
import "./Footer.css";

const Footer = () => {
  const [email, setEmail] = useState("");
  const [subscribed, setSubscribed] = useState(false);

  const handleSubscribe = (e) => {
    e.preventDefault();
    if (email.trim()) {
      setSubscribed(true);
      setEmail("");
    }
  };

  return (
    <footer className="footer">
      <div className="footer-inner">
        {/* Newsletter */}
        <div className="newsletter-section">
          <div className="newsletter-text">
            <h2 className="newsletter-title">Stay in the Loop</h2>
            <p className="newsletter-sub">
              Get early access to new drops, exclusive deals & style inspo. No spam, ever.
            </p>
          </div>
          {subscribed ? (
            <div className="subscribed-msg">
              <span>✓</span> You're in! Welcome to ShopWave.
            </div>
          ) : (
            <form className="newsletter-form" onSubmit={handleSubscribe}>
              <input
                type="email"
                placeholder="your@email.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
              <button type="submit">Subscribe</button>
            </form>
          )}
        </div>

        <div className="footer-divider" />

        {/* Main footer links */}
        <div className="footer-main">
          {/* Brand */}
          <div className="footer-brand">
            <div className="footer-logo">
              <span className="logo-icon">◈</span>
              <span className="logo-text">ShopWave</span>
            </div>
            <p className="footer-tagline">
              Premium fashion & lifestyle essentials, curated for the modern Indian consumer.
            </p>
            <div className="social-links">
              {["Instagram", "Twitter", "Facebook", "Pinterest"].map((s) => (
                <a key={s} href="#" className="social-link">{s[0]}</a>
              ))}
            </div>
          </div>

          {/* Links */}
          {[
            {
              title: "Shop",
              links: ["New Arrivals", "Clothing", "Footwear", "Accessories", "Bags", "Sale"],
            },
            {
              title: "Help",
              links: ["Track Order", "Returns", "Size Guide", "FAQ", "Contact Us"],
            },
            {
              title: "Company",
              links: ["About Us", "Careers", "Press", "Privacy Policy", "Terms"],
            },
          ].map((col) => (
            <div key={col.title} className="footer-col">
              <h4 className="footer-col-title">{col.title}</h4>
              <ul className="footer-col-links">
                {col.links.map((l) => (
                  <li key={l}><a href="#">{l}</a></li>
                ))}
              </ul>
            </div>
          ))}
        </div>

        <div className="footer-divider" />

        {/* Bottom bar */}
        <div className="footer-bottom">
          <p>© 2026 ShopWave. All rights reserved.</p>
          <div className="payment-badges">
            {["UPI", "Visa", "Mastercard", "GPay"].map((p) => (
              <span key={p} className="pay-badge">{p}</span>
            ))}
          </div>
          <p className="footer-made">Made with ♥ in India</p>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
